# --- SYSTEM context removal (v8) ---
Get-Process OneDrive -ErrorAction SilentlyContinue | Stop-Process -Force
$paths = @(
    "$env:SystemRoot\System32\OneDriveSetup.exe",
    "$env:SystemRoot\SysWOW64\OneDriveSetup.exe"
)
foreach ($p in $paths) {
    if (Test-Path $p) { Start-Process $p "/uninstall" -Wait }
}

# --- User context removal (v2) ---
# Deployed separately — targets per-user install
# Must run in USER context via Intune

# Self-elevate: paste at top of any script
if (-not ([Security.Principal.WindowsPrincipal] [Security.Principal.WindowsIdentity]::GetCurrent()
  ).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)) {
    Start-Process powershell.exe "-ExecutionPolicy Bypass -File \"$PSCommandPath\"" -Verb RunAs
    exit
}
Write-Host "Running elevated..." -ForegroundColor Green

$regPath = "HKLM:\SOFTWARE\Microsoft\Office\ClickToRun\Configuration"
$regValue = "ProductReleaseIds"
$expected = "ProPlus2024Volume"

try {
    $val = (Get-ItemProperty -Path $regPath -Name $regValue -ErrorAction Stop).$regValue
    if ($val -match $expected) {
        Write-Host "Detected"
        exit 0
    }
} catch {}
Write-Host "Not detected"
exit 1

# Simple file check
$targetFile = "C:\Program Files\AppName\app.exe"
if (Test-Path $targetFile) {
    Write-Host "Detected"; exit 0
}
Write-Host "Not detected"; exit 1

# With version check
$targetFile = "C:\Program Files\AppName\app.exe"
$requiredVersion = "2.1.0"
if (Test-Path $targetFile) {
    $ver = (Get-Item $targetFile).VersionInfo.ProductVersion
    if ([version]$ver -ge [version]$requiredVersion) {
        Write-Host "Detected v$ver"; exit 0
    }
}
Write-Host "Not detected"; exit 1

# Install path (hash varies per deployment)
# C:\Program Files\BeyondTrust\bomgar-scc\[hash]\bomgar-scc.exe

$btPath = "C:\Program Files\BeyondTrust\bomgar-scc"
if (Test-Path $btPath) {
    $exe = Get-ChildItem -Path $btPath -Recurse -Filter "bomgar-scc.exe" -EA SilentlyContinue
    if ($exe) { Write-Host "Detected"; exit 0 }
}
Write-Host "Not detected"; exit 1

# Uninstall GUID — confirm per deployment
# Check: HKLM:\SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall

# --- Basic try/catch ---
try {
    Get-Item "C:\nonexistent" -ErrorAction Stop
} catch {
    Write-Host "Error: $($_.Exception.Message)" -ForegroundColor Red
} finally {
    Write-Host "Cleanup code runs regardless"
}

# --- ErrorAction values ---
# Stop       = throw terminating error (for try/catch)
# Continue   = show error, keep going (default)
# SilentlyContinue = hide error, keep going
# Inquire    = ask user

# --- $ErrorActionPreference (script-wide) ---
$ErrorActionPreference = 'Stop'  # Make all errors catchable

# --- Log errors ---
try {
    # risky code
} catch {
    $_ | Out-File "C:\Logs\errors.log" -Append
    throw  # re-throw to caller
}

# --- Check last exit code (for native commands) ---
cmd /c "exit 1"
if ($LASTEXITCODE -ne 0) { Write-Host "Command failed with code $LASTEXITCODE" }

# All USB storage devices (registry)
Get-ItemProperty -Path 'HKLM:\SYSTEM\CurrentControlSet\Enum\USBSTOR\*\*' | Select FriendlyName, Mfg

# Detailed USB history
Get-WinEvent -FilterHashtable @{LogName='Microsoft-Windows-DriverFrameworks-UserMode/Operational'; ID=2003} -MaxEvents 20 | ForEach-Object {
    [PSCustomObject]@{
        Time = $_.TimeCreated
        Message = $_.Message
    }
}

# CMD approach
# reg query HKLM\SYSTEM\CurrentControlSet\Enum\USBSTOR /s

# List currently connected USB
Get-PnpDevice -Class USB | Where Status -eq 'OK' | Select FriendlyName,InstanceId
